const stylesheetCache = new Map<string, CSSStyleSheet>();

// Prepended to every component sheet so the HTML `[hidden]` attribute reliably
// hides elements even when an author rule sets `display: …` on the same node.
// Shadow DOM blocks the document-level UA `[hidden]` rule from being raised in
// specificity from outside, so we inject this once per sheet at the helper
// level — every shadow root that goes through `cssStyleSheet` gets it for free.
// See DLR #133.
const GLOBAL_PRELUDE = `[hidden]{display:none!important}`;

export function cssStyleSheet(cssText: string): CSSStyleSheet {
    // TODO: Remove this helper once Vite supports `import ... with { type: 'css' }`
    // as a real `CSSStyleSheet` export in both dev and build.
    const fullText = GLOBAL_PRELUDE + cssText;
    const cached = stylesheetCache.get(fullText);
    if (cached) {
        return cached;
    }

    const sheet = new CSSStyleSheet();
    sheet.replaceSync(fullText);
    stylesheetCache.set(fullText, sheet);
    return sheet;
}

const documentSheetCache = new Map<string, CSSStyleSheet>();

/**
 * Adopt a stylesheet at the **document** level — for light-DOM *screens* that
 * can't use a shadow root (they render the global section-page chrome via
 * `buildSectionPage`, which only styles light DOM). Builds a cached constructable
 * sheet and adopts it into `document.adoptedStyleSheets` idempotently, so the
 * call is a one-liner at module load.
 *
 * Unlike `cssStyleSheet`, there is **no `[hidden]` prelude**: document scope
 * already gets the UA `[hidden]` rule, and injecting an app-wide
 * `[hidden]{display:none!important}` from a single screen's import would be a
 * surprising global side effect (the prelude exists only because shadow roots
 * block the UA rule — see DLR #133).
 */
export function documentStyleSheet(cssText: string): CSSStyleSheet {
    const cached = documentSheetCache.get(cssText);
    if (cached) {
        return cached;
    }

    const sheet = new CSSStyleSheet();
    sheet.replaceSync(cssText);
    documentSheetCache.set(cssText, sheet);

    if (!document.adoptedStyleSheets.includes(sheet)) {
        document.adoptedStyleSheets = [...document.adoptedStyleSheets, sheet];
    }
    return sheet;
}
